import math

def _matrix_add(A, B):
    n = len(A)
    C = [[0 for _ in range(n)] for _ in range(n)]
    for i in range(n):
        for j in range(n):
            C[i][j] = A[i][j] + B[i][j]
    return C

def _matrix_sub(A, B):
    n = len(A)
    C = [[0 for _ in range(n)] for _ in range(n)]
    for i in range(n):
        for j in range(n):
            C[i][j] = A[i][j] - B[i][j]
    return C

def _naive_multiply(A, B):
    m = len(A)
    n = len(A[0])
    p = len(B[0])
    C = [[0 for _ in range(p)] for _ in range(m)]
    for i in range(m):
        for j in range(p):
            for k in range(n):
                C[i][j] += A[i][k] * B[k][j]
    return C

def _split_matrix(matrix):
    n = len(matrix)
    half = n // 2
    A11 = [[0 for _ in range(half)] for _ in range(half)]
    A12 = [[0 for _ in range(half)] for _ in range(half)]
    A21 = [[0 for _ in range(half)] for _ in range(half)]
    A22 = [[0 for _ in range(half)] for _ in range(half)]

    for i in range(half):
        for j in range(half):
            A11[i][j] = matrix[i][j]
            A12[i][j] = matrix[i][j + half]
            A21[i][j] = matrix[i + half][j]
            A22[i][j] = matrix[i + half][j + half]
    return A11, A12, A21, A22

def _join_matrices(C11, C12, C21, C22):
    half = len(C11)
    n = half * 2
    matrix = [[0 for _ in range(n)] for _ in range(n)]

    for i in range(half):
        for j in range(half):
            matrix[i][j] = C11[i][j]
            matrix[i][j + half] = C12[i][j]
            matrix[i + half][j] = C21[i][j]
            matrix[i + half][j + half] = C22[i][j]
    return matrix

def _strassen_recursive(A, B, threshold):
    n = len(A)

    if n <= threshold:
        return _naive_multiply(A, B)

    A11, A12, A21, A22 = _split_matrix(A)
    B11, B12, B21, B22 = _split_matrix(B)

    P1 = _strassen_recursive(A11, _matrix_sub(B12, B22), threshold)
    P2 = _strassen_recursive(_matrix_add(A11, A12), B22, threshold)
    P3 = _strassen_recursive(_matrix_add(A21, A22), B11, threshold)
    P4 = _strassen_recursive(A22, _matrix_sub(B21, B11), threshold)
    P5 = _strassen_recursive(_matrix_add(A11, A22), _matrix_add(B11, B22), threshold)
    P6 = _strassen_recursive(_matrix_sub(A12, A22), _matrix_add(B21, B22), threshold)
    P7 = _strassen_recursive(_matrix_sub(A11, A21), _matrix_add(B11, B12), threshold)

    C11 = _matrix_add(_matrix_sub(_matrix_add(P5, P4), P2), P6)
    C12 = _matrix_add(P1, P2)
    C21 = _matrix_add(P3, P4)
    C22 = _matrix_sub(_matrix_sub(_matrix_add(P5, P1), P3), P7)

    return _join_matrices(C11, C12, C21, C22)

def strassen_multiply(A, B, threshold=16):
    m1 = len(A)
    n1 = len(A[0])
    m2 = len(B)
    n2 = len(B[0])

    if n1 != m2:
        raise ValueError("Matrices dimensions are not compatible for multiplication.")

    max_dim = max(m1, n1, n2)

    if max_dim & (max_dim - 1) == 0:
        N = max_dim
    else:
        N = 1 << (max_dim - 1).bit_length()

    padded_A = [[0 for _ in range(N)] for _ in range(N)]
    padded_B = [[0 for _ in range(N)] for _ in range(N)]

    for i in range(m1):
        for j in range(n1):
            padded_A[i][j] = A[i][j]

    for i in range(m2):
        for j in range(n2):
            padded_B[i][j] = B[i][j]

    result_padded = _strassen_recursive(padded_A, padded_B, threshold)

    final_result = [[0 for _ in range(n2)] for _ in range(m1)]
    for i in range(m1):
        for j in range(n2):
            final_result[i][j] = result_padded[i][j]

    return final_result
